body.value:
{%- style -%}
  .romira-stages-{{ section.id }} {
    padding-top: {{ section.settings.mobile_padding_top }}px;
    padding-bottom: {{ section.settings.mobile_padding_bottom }}px;
    background-color: {{ section.settings.background_color }};
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} {
      padding-top: {{ section.settings.padding_top }}px;
      padding-bottom: {{ section.settings.padding_bottom }}px;
    }
  }
  .romira-stages-{{ section.id }} .rs-inner {
    max-width: {{ section.settings.content_width }}px;
    margin: 0 auto;
    padding: 0 {{ section.settings.horizontal_padding_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-inner {
      padding: 0 {{ section.settings.horizontal_padding }}px;
    }
  }
  .romira-stages-{{ section.id }} .rs-header {
    text-align: {{ section.settings.heading_alignment }};
    margin-bottom: 40px;
  }
  .romira-stages-{{ section.id }} .rs-heading {
    font-size: {{ section.settings.heading_size_mobile }}px;
    color: {{ section.settings.heading_color }};
    margin: 0 0 12px;
    line-height: 1.2;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-heading {
      font-size: {{ section.settings.heading_size }}px;
    }
  }
  .romira-stages-{{ section.id }} .rs-subheading {
    font-size: 16px;
    color: {{ section.settings.subheading_color }};
    margin: 0 auto;
    max-width: 700px;
    line-height: 1.5;
  }
  .romira-stages-{{ section.id }} .rs-blocks {
    display: flex;
    flex-direction: column;
    gap: {{ section.settings.block_gap_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-blocks {
      flex-direction: row;
      align-items: flex-start;
      gap: 0;
    }
  }
  .romira-stages-{{ section.id }} .rs-block {
    background: {{ section.settings.block_bg_color }};
    border-radius: {{ section.settings.block_border_radius }}px;
    overflow: hidden;
    border: 1px solid {{ section.settings.block_border_color }};
    flex: 1;
    min-width: 0;
  }
  .romira-stages-{{ section.id }} .rs-block img {
    width: 100%;
    display: block;
    object-fit: cover;
    aspect-ratio: {{ section.settings.image_ratio }};
  }
  .romira-stages-{{ section.id }} .rs-block-placeholder {
    width: 100%;
    aspect-ratio: {{ section.settings.image_ratio }};
    background: #e8e8e8;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #999;
    font-size: 14px;
  }
  .romira-stages-{{ section.id }} .rs-block-content {
    padding: {{ section.settings.block_padding_mobile }}px;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-block-content {
      padding: {{ section.settings.block_padding }}px;
    }
  }
  .romira-stages-{{ section.id }} .rs-stage-label {
    font-size: 11px;
    font-weight: 700;
    letter-spacing: 1.5px;
    text-transform: uppercase;
    color: {{ section.settings.stage_label_color }};
    margin: 0 0 8px;
  }
  .romira-stages-{{ section.id }} .rs-block-heading {
    font-size: {{ section.settings.block_heading_size_mobile }}px;
    color: {{ section.settings.block_heading_color }};
    margin: 0 0 10px;
    line-height: 1.3;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-block-heading {
      font-size: {{ section.settings.block_heading_size }}px;
    }
  }
  .romira-stages-{{ section.id }} .rs-block-text {
    font-size: {{ section.settings.block_text_size }}px;
    color: {{ section.settings.block_text_color }};
    line-height: 1.6;
    margin: 0;
  }
  .romira-stages-{{ section.id }} .rs-block-text p { margin: 0; }
  .romira-stages-{{ section.id }} .rs-arrow {
    display: none;
  }
  @media screen and (min-width: 750px) {
    .romira-stages-{{ section.id }} .rs-arrow {
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      width: {{ section.settings.arrow_width }}px;
      padding-bottom: {{ section.settings.arrow_offset }}px;
    }
    .romira-stages-{{ section.id }} .rs-arrow svg {
      width: 20px;
      height: 20px;
    }
  }
{%- endstyle -%}

<div class="romira-stages-{{ section.id }}">
  <div class="rs-inner">
    {%- if section.settings.heading != blank or section.settings.subheading != blank -%}
      <div class="rs-header">
        {%- if section.settings.heading != blank -%}
          <{{ section.settings.heading_tag }} class="rs-heading">{{ section.settings.heading }}</{{ section.settings.heading_tag }}>
        {%- endif -%}
        {%- if section.settings.subheading != blank -%}
          <p class="rs-subheading">{{ section.settings.subheading }}</p>
        {%- endif -%}
      </div>
    {%- endif -%}
    <div class="rs-blocks">
      {%- for block in section.blocks -%}
        <div class="rs-block" {{ block.shopify_attributes }}>
          {%- if block.settings.image != blank -%}
            {{ block.settings.image | image_url: width: 600 | image_tag: loading: 'lazy' }}
          {%- else -%}
            <div class="rs-block-placeholder">Add image</div>
          {%- endif -%}
          <div class="rs-block-content">
            {%- if block.settings.stage_label != blank -%}
              <p class="rs-stage-label">{{ block.settings.stage_label }}</p>
            {%- endif -%}
            {%- if block.settings.heading != blank -%}
              <h3 class="rs-block-heading">{{ block.settings.heading }}</h3>
            {%- endif -%}
            {%- if block.settings.text != blank -%}
              <div class="rs-block-text">{{ block.settings.text }}</div>
            {%- endif -%}
          </div>
        </div>
        {%- unless forloop.last -%}
          <div class="rs-arrow">
            <svg viewBox="0 0 20 20" fill="{{ section.settings.arrow_color }}"><path d="M7 4l6 6-6 6" stroke="{{ section.settings.arrow_color }}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" fill="none"/></svg>
          </div>
        {%- endunless -%}
      {%- endfor -%}
    </div>
  </div>
</div>

{% schema %}
{
  "name": "Romira — Nerve Stages",
  "tag": "section",
  "class": "section",
  "settings": [
    { "type": "text", "id": "heading", "label": "Heading", "default": "The 3 Stages of Nerve Breakdown" },
    { "type": "select", "id": "heading_tag", "label": "Heading tag", "options": [{"value":"h1","label":"H1"},{"value":"h2","label":"H2"},{"value":"h3","label":"H3"}], "default": "h2" },
    { "type": "range", "id": "heading_size", "min": 20, "max": 60, "step": 2, "unit": "px", "label": "Heading size (desktop)", "default": 36 },
    { "type": "range", "id": "heading_size_mobile", "min": 16, "max": 48, "step": 2, "unit": "px", "label": "Heading size (mobile)", "default": 26 },
    { "type": "select", "id": "heading_alignment", "label": "Heading alignment", "options": [{"value":"left","label":"Left"},{"value":"center","label":"Center"},{"value":"right","label":"Right"}], "default": "center" },
    { "type": "text", "id": "subheading", "label": "Subheading", "default": "Most nerve discomfort builds through predictable stages. Recognising yours is the first step." },
    { "type": "color", "id": "heading_color", "label": "Heading color", "default": "#1a1a1a" },
    { "type": "color", "id": "subheading_color", "label": "Subheading color", "default": "#555555" },
    { "type": "color", "id": "background_color", "label": "Background color", "default": "#ffffff" },
    { "type": "color", "id": "block_bg_color", "label": "Card background", "default": "#ffffff" },
    { "type": "color", "id": "block_border_color", "label": "Card border color", "default": "#e8e8e8" },
    { "type": "range", "id": "block_border_radius", "min": 0, "max": 24, "step": 2, "unit": "px", "label": "Card border radius", "default": 12 },
    { "type": "color", "id": "stage_label_color", "label": "Stage label color", "default": "#264165" },
    { "type": "color", "id": "block_heading_color", "label": "Card heading color", "default": "#1a1a1a" },
    { "type": "color", "id": "block_text_color", "label": "Card text color", "default": "#444444" },
    { "type": "color", "id": "arrow_color", "label": "Arrow color", "default": "#264165" },
    { "type": "range", "id": "arrow_width", "min": 20, "max": 60, "step": 4, "unit": "px", "label": "Arrow width", "default": 32 },
    { "type": "range", "id": "arrow_offset", "min": 0, "max": 200, "step": 4, "unit": "px", "label": "Arrow vertical offset", "default": 80 },
    { "type": "select", "id": "image_ratio", "label": "Image ratio", "options": [{"value":"1","label":"Square"},{"value":"0.667","label":"3:2"},{"value":"0.5625","label":"16:9"}], "default": "0.667" },
    { "type": "range", "id": "block_gap_mobile", "min": 8, "max": 48, "step": 4, "unit": "px", "label": "Gap (mobile)", "default": 16 },
    { "type": "range", "id": "block_padding", "min": 8, "max": 48, "step": 4, "unit": "px", "label": "Card padding (desktop)", "default": 24 },
    { "type": "range", "id": "block_padding_mobile", "min": 8, "max": 48, "step": 4, "unit": "px", "label": "Card padding (mobile)", "default": 20 },
    { "type": "range", "id": "block_heading_size", "min": 14, "max": 32, "step": 1, "unit": "px", "label": "Card heading (desktop)", "default": 20 },
    { "type": "range", "id": "block_heading_size_mobile", "min": 14, "max": 32, "step": 1, "unit": "px", "label": "Card heading (mobile)", "default": 18 },
    { "type": "range", "id": "block_text_size", "min": 12, "max": 20, "step": 1, "unit": "px", "label": "Card text size", "default": 15 },
    { "type": "range", "id": "content_width", "min": 600, "max": 1400, "step": 20, "unit": "px", "label": "Max content width", "default": 1200 },
    { "type": "range", "id": "horizontal_padding", "min": 0, "max": 80, "step": 4, "unit": "px", "label": "Horizontal padding (desktop)", "default": 20 },
    { "type": "range", "id": "horizontal_padding_mobile", "min": 0, "max": 40, "step": 4, "unit": "px", "label": "Horizontal padding (mobile)", "default": 16 },
    { "type": "header", "content": "Spacing" },
    { "type": "range", "id": "padding_top", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding top (desktop)", "default": 60 },
    { "type": "range", "id": "padding_bottom", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding bottom (desktop)", "default": 60 },
    { "type": "range", "id": "mobile_padding_top", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding top (mobile)", "default": 36 },
    { "type": "range", "id": "mobile_padding_bottom", "min": 0, "max": 120, "step": 4, "unit": "px", "label": "Padding bottom (mobile)", "default": 36 }
  ],
  "blocks": [
    {
      "type": "stage",
      "name": "Stage",
      "settings": [
        { "type": "image_picker", "id": "image", "label": "Stage image" },
        { "type": "text", "id": "stage_label", "label": "Stage label", "default": "STAGE 1" },
        { "type": "text", "id": "heading", "label": "Heading", "default": "Early Warning Signs" },
        { "type": "richtext", "id": "text", "label": "Description", "default": "<p>Occasional tingling or numbness in the hands and feet. Usually worse at night. Most people assume it will pass on its own.</p>" }
      ]
    }
  ],
  "presets": [
    {
      "name": "Romira — Nerve Stages",
      "blocks": [
        { "type": "stage", "settings": { "stage_label": "STAGE 1", "heading": "Early Warning Signs", "text": "<p>Occasional tingling or numbness in hands and feet. Usually worse at night. Most people assume it will pass — and ignore it for months.</p>" } },
        { "type": "stage", "settings": { "stage_label": "STAGE 2", "heading": "The Discomfort Sets In", "text": "<p>Burning, electric shocks, and pins-and-needles become daily. Sleep suffers. Simple tasks — walking, holding objects — become uncomfortable.</p>" } },
        { "type": "stage", "settings": { "stage_label": "STAGE 3", "heading": "Your World Gets Smaller", "text": "<p>Chronic nerve discomfort limits mobility, disrupts sleep, and affects mood. Many have tried multiple approaches with little lasting relief. This is where R-ALA works differently.</p>" } }
      ]
    }
  ]
}
{% endschema %}
